import{c as s,Q as a,j as t,m as n}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Checkout — for issuers","description":"Mint a checkout link, share it, monitor it.","frontmatter":{"title":"Checkout — for issuers","description":"Mint a checkout link, share it, monitor it."},"headers":[],"relativePath":"checkout/for-issuers.md","filePath":"checkout/for-issuers.md","lastUpdated":1780196777000}'),i={name:"checkout/for-issuers.md"};function o(l,e,p,h,r,c){return a(),t("div",null,[...e[0]||(e[0]=[n(`<div class="warning custom-block"><p class="custom-block-title">🚧 In development — not in the Testing Guide</p><p>This surface is still being hardened and isn&#39;t part of the <a href="/guide/">Testing Guide</a>. The page below describes the intended design. To evaluate MuHaven today, use <a href="/havenbot/overview">HavenBot</a> or the <a href="/mcp/overview">MCP server</a>.</p></div><h1 id="hosted-checkout-—-for-issuers" tabindex="-1">Hosted Checkout — for issuers <a class="header-anchor" href="#hosted-checkout-—-for-issuers" aria-label="Permalink to &quot;Hosted Checkout — for issuers&quot;">​</a></h1><p>You&#39;re an approved issuer and you want to sell some of your RWA token to a specific buyer (or batch of buyers) without onboarding each one into your KYC whitelist. Hosted Checkout is the surface for that.</p><p>The end-to-end loop:</p><ol><li>Mint a link via HavenBot.</li><li>Share it.</li><li>Watch the SSE channel (or your webhook URL) for the settlement notification.</li><li>(Optionally) cancel an unredeemed link.</li></ol><h2 id="step-1-—-mint-the-link" tabindex="-1">Step 1 — Mint the link <a class="header-anchor" href="#step-1-—-mint-the-link" aria-label="Permalink to &quot;Step 1 — Mint the link&quot;">​</a></h2><p>In HavenBot, ask:</p><blockquote><p>Create a checkout for 500 mhUSDC of RWA1 expiring in 24 hours.</p></blockquote><p>HavenBot calls the <code>create_checkout</code> tool (an issuer-only tool that lives in HavenBot&#39;s <code>muhaven_*</code> namespace). The ConfirmModal renders a preview:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Create checkout link</span></span>
<span class="line"><span>─────────────────────</span></span>
<span class="line"><span>  Token:          RWA1</span></span>
<span class="line"><span>  Amount:         500 mhUSDC</span></span>
<span class="line"><span>  Expires:        in 24 hours (2026-05-17 11:42 UTC)</span></span>
<span class="line"><span>  Webhook:        (none)</span></span>
<span class="line"><span>  Buyer:          (any holder of a valid passkey)</span></span>
<span class="line"><span>  Label:          (auto: &quot;RWA1 — 500 mhUSDC&quot;)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  [Cancel]                              [Confirm]</span></span></code></pre></div><p>Confirm with your passkey. HavenBot replies:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Created checkout chk_01HMTV9X...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>🔗 Link: https://muhaven.app/pay/c/01HMTV9X.../#k=AbCdEfGhIjKlMnOpQrStUvWxYz123456</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Share this link with your buyer. The fragment after # is the</span></span>
<span class="line"><span>decryption key — if you share the link with the # part stripped,</span></span>
<span class="line"><span>the buyer will get a &quot;Session not found&quot; error.</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">Don&#39;t lose the fragment</p><p>Telegram, Twitter, and Slack reliably preserve URL fragments when pasted as links. Markdown link syntax (<code>[text](url)</code>) on platforms that mangle fragments may strip the <code>#k=...</code> part. If you&#39;re sharing across a known fragment-stripping channel, share the URL as plain text instead of a hyperlink.</p></div><h2 id="step-2-—-optional-webhook-setup" tabindex="-1">Step 2 — Optional webhook setup <a class="header-anchor" href="#step-2-—-optional-webhook-setup" aria-label="Permalink to &quot;Step 2 — Optional webhook setup&quot;">​</a></h2><p>If you want real-time programmatic notifications (instead of polling), set up a webhook:</p><blockquote><p>Create a checkout for 1000 mhUSDC of RWA2 with webhook <a href="https://my.api/cb" target="_blank" rel="noreferrer">https://my.api/cb</a> expiring in 12 hours.</p></blockquote><p>HavenBot&#39;s preview adds:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>  Webhook:        https://my.api/cb (will be signed with whsec_...)</span></span></code></pre></div><p>Confirm with your passkey. The backend generates a unique <code>whsec_&lt;32-hex&gt;</code> per checkout session, stored against the session row. Every webhook delivery to <code>https://my.api/cb</code> carries:</p><ul><li><code>Content-Type: application/json</code></li><li><code>MuHaven-Signature: t=&lt;unix&gt;,v1=&lt;HMAC-SHA256(t.body, whsec_...)&gt;</code></li><li><code>Idempotency-Key: &lt;ulid&gt;</code> for dedupe</li></ul><p>See <a href="/checkout/webhooks">Webhooks &amp; receipts</a> for the verifier code and replay-window semantics.</p><h2 id="step-3-—-watch-the-settlement" tabindex="-1">Step 3 — Watch the settlement <a class="header-anchor" href="#step-3-—-watch-the-settlement" aria-label="Permalink to &quot;Step 3 — Watch the settlement&quot;">​</a></h2><p>Three ways to know when the buyer paid:</p><h3 id="a-havenbot-sse-notification" tabindex="-1">A. HavenBot SSE notification <a class="header-anchor" href="#a-havenbot-sse-notification" aria-label="Permalink to &quot;A. HavenBot SSE notification&quot;">​</a></h3><p>HavenBot subscribes to your issuer-side SSE channel when you mint a checkout. As soon as the buyer&#39;s UserOp settles, HavenBot says:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ chk_01HMTV9X... paid</span></span>
<span class="line"><span>   Buyer: 0xabc...123 (first-time MuHaven wallet)</span></span>
<span class="line"><span>   Amount: 500 mhUSDC</span></span>
<span class="line"><span>   Token: RWA1</span></span>
<span class="line"><span>   Settled in tx: 0xdef...</span></span>
<span class="line"><span>   View on Arbiscan</span></span></code></pre></div><h3 id="b-your-webhook-url" tabindex="-1">B. Your webhook URL <a class="header-anchor" href="#b-your-webhook-url" aria-label="Permalink to &quot;B. Your webhook URL&quot;">​</a></h3><p>If you registered a webhook, your endpoint receives a POST:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;evt_01HMTV...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;type&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;checkout.session.paid&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;session_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;chk_01HMTV9X...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;issuer_user_id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;usr_...&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;token&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;RWA1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;amount_usd6&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">500000000</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;buyer_wallet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0xabc...123&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;settled_at&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-05-16T11:43:21Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;tx_hash&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0xdef...&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>Verify the signature, then act.</p><h3 id="c-polling" tabindex="-1">C. Polling <a class="header-anchor" href="#c-polling" aria-label="Permalink to &quot;C. Polling&quot;">​</a></h3><p>Ask HavenBot:</p><blockquote><p>What&#39;s the status of checkout chk_01HMTV9X...?</p></blockquote><p>Replies with the current status: <code>pending</code> / <code>paid</code> / <code>expired</code> / <code>cancelled</code>.</p><h2 id="step-4-—-cancel-an-unredeemed-link" tabindex="-1">Step 4 — Cancel an unredeemed link <a class="header-anchor" href="#step-4-—-cancel-an-unredeemed-link" aria-label="Permalink to &quot;Step 4 — Cancel an unredeemed link&quot;">​</a></h2><p>If you change your mind before the buyer pays:</p><blockquote><p>Cancel checkout chk_01HMTV9X...</p></blockquote><p>HavenBot opens a ConfirmModal; confirm with your passkey. The backend flips the session row to <code>cancelled</code> and stops accepting payment attempts. If the buyer&#39;s link is still in their messages, they&#39;ll get a &quot;Session cancelled&quot; page on click.</p><p>You <strong>can&#39;t</strong> cancel a paid session — it&#39;s already on-chain.</p><h2 id="listing-your-checkout-sessions" tabindex="-1">Listing your checkout sessions <a class="header-anchor" href="#listing-your-checkout-sessions" aria-label="Permalink to &quot;Listing your checkout sessions&quot;">​</a></h2><blockquote><p>Show me my recent checkouts.</p></blockquote><p>HavenBot calls the <code>list_checkouts</code> tool and renders a table:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>ID                    Token   Amount   Status      Created             Expires</span></span>
<span class="line"><span>chk_01HMTV9X...       RWA1  500.00   paid        2026-05-15 11:42    -</span></span>
<span class="line"><span>chk_01HMTV8Y...       RWA2   1000.00  pending     2026-05-16 09:14    2026-05-16 21:14</span></span>
<span class="line"><span>chk_01HMTV7Z...       RWA3   250.00   expired     2026-05-14 16:00    2026-05-15 04:00</span></span>
<span class="line"><span>chk_01HMTV6W...       RWA1  750.00   cancelled   2026-05-13 12:00    -</span></span></code></pre></div><p>You can filter:</p><blockquote><p>Show me my checkouts that are still pending.</p></blockquote><p>Or:</p><blockquote><p>Show me checkouts paid in the last week.</p></blockquote><h2 id="composite-indexes-for-fast-queries" tabindex="-1">Composite indexes for fast queries <a class="header-anchor" href="#composite-indexes-for-fast-queries" aria-label="Permalink to &quot;Composite indexes for fast queries&quot;">​</a></h2><p>The <code>checkout_sessions</code> table has a composite index on <code>(issuer_user_id, status, created_at)</code> so the dashboard&#39;s list view stays fast even at scale. You don&#39;t need to do anything special — just know that querying by issuer + status returns in &lt;10ms even with millions of rows.</p><h2 id="privacy-properties" tabindex="-1">Privacy properties <a class="header-anchor" href="#privacy-properties" aria-label="Permalink to &quot;Privacy properties&quot;">​</a></h2><ul><li><strong>The fragment key never reaches our server.</strong> Your operator can&#39;t decrypt the session payload — they only have ciphertext.</li><li><strong>The buyer&#39;s wallet address</strong> is logged in the audit row only <strong>after</strong> payment (i.e., the operator learns who paid once payment settles, but the buyer&#39;s identity isn&#39;t exposed pre-payment).</li><li><strong>The webhook secret</strong> (<code>whsec_...</code>) is per-session and never reused.</li><li><strong>The audit log</strong> records <code>checkout_created</code> + <code>checkout_paid</code> + <code>checkout_expired</code> + <code>checkout_cancelled</code> — full forensic trail.</li></ul><h2 id="what-hosted-checkout-doesn-t-do" tabindex="-1">What hosted checkout doesn&#39;t do <a class="header-anchor" href="#what-hosted-checkout-doesn-t-do" aria-label="Permalink to &quot;What hosted checkout doesn&#39;t do&quot;">​</a></h2><ul><li><strong>Recurring billing.</strong> Each checkout is one-shot. No subscription primitive today.</li><li><strong>Buy-and-claim in one flow.</strong> Buyer-side flows always settle in the buy step; claim is a separate user action on their dashboard.</li><li><strong>Refunds.</strong> The on-chain Subscription contract doesn&#39;t support refunds. If you over-charged, mint a yield distribution back to the buyer.</li><li><strong>Per-buyer KYC enforcement.</strong> The KYC whitelist is at the token level. If your token is on KYC mode and the buyer isn&#39;t whitelisted, the buy reverts. There&#39;s no &quot;whitelist-on-payment&quot; preset.</li></ul><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/checkout/for-buyers">For buyers</a> — what your buyer experiences.</li><li><a href="/checkout/fragment-key">URL fragment key</a> — the privacy property in detail.</li><li><a href="/checkout/webhooks">Webhooks &amp; receipts</a> — signing, replay window, idempotency.</li><li><a href="/checkout/troubleshooting">Troubleshooting</a> — common issuer-side issues.</li></ul>`,55)])])}const k=s(i,[["render",o]]);export{u as __pageData,k as default};
